commands.cmd:
if [ -n "${HOSTLENS_REDIS_PASSWORD:-}" ]; then
  count=$(REDISCLI_AUTH="$HOSTLENS_REDIS_PASSWORD" redis-cli --no-auth-warning -t 5 -h 127.0.0.1 -p 6379 --json SLOWLOG LEN) || { echo "redis SLOWLOG LEN failed" >&2; exit 1; }
else
  count=$(redis-cli -t 5 -h 127.0.0.1 -p 6379 --json SLOWLOG LEN) || { echo "redis SLOWLOG LEN failed" >&2; exit 1; }
fi
case "$count" in ''|*[!0-9]*) echo "redis SLOWLOG LEN non-numeric: $count" >&2; exit 1;; esac
if [ -n "${HOSTLENS_REDIS_PASSWORD:-}" ]; then
  max_micros=$(REDISCLI_AUTH="$HOSTLENS_REDIS_PASSWORD" redis-cli --no-auth-warning -t 5 -h 127.0.0.1 -p 6379 EVAL 'local r=redis.call("SLOWLOG","GET",tonumber(ARGV[1])); local m=0; for i,e in ipairs(r) do if e[3]>m then m=e[3] end end; return m' 0 1024) || { echo "redis EVAL failed" >&2; exit 1; }
else
  max_micros=$(redis-cli -t 5 -h 127.0.0.1 -p 6379 EVAL 'local r=redis.call("SLOWLOG","GET",tonumber(ARGV[1])); local m=0; for i,e in ipairs(r) do if e[3]>m then m=e[3] end end; return m' 0 1024) || { echo "redis EVAL failed" >&2; exit 1; }
fi
case "$max_micros" in ''|*[!0-9]*) echo "redis EVAL non-numeric: $max_micros" >&2; exit 1;; esac
printf '{"count":%d,"max_micros":%d}' "$count" "$max_micros"
